      "n": 44,
      "column": "left",
      "text": "Un tas KUNGS runna-\nja us Mohsu/ un fazzija:"
    },
    {
      "n": 45,
      "column": "left",
      "text": "Zelleetees no schahs\nDraudses/ tad aprihscbu Es to\nAzzumirkti/ tad fritte tee us sa-\nwu Watgu."
    },
    {
      "n": 46,
      "column": "left",
      "text": "Un Mohsus fazzija us A-\naronn: Neit to Kwehpja-Trau-\nfu/ un leez Ugguni eeksch ta no\nta Altara/ un leez Kwehpja-Sah-\nles wirfu/ un eij drihsi pee to\nDraudsi/ un darri Salihdsina-\nschann par teem/ jo ta Bahrsti-\nba irr no ta KUNGA isgahju-\nsi/ un ta Mohziba irr cefahnuft."
    },
    {
      "n": 47,
      "column": "left",
      "text": "Un Aarons nehme to/\nttin fa Mohsus runnajts bij/ un\ntezzeja starp tahs Draudses/ un\nraugi/ ta Mohziba bij eefahnuft\nstarp teem Landuun/ un wiꞥsch\nlikke Kwehpja-Sahles wirfu/ un\ndarrija Salihdsinafchanu par\nteem Landim."
    },
    {
      "n": 48,
      "column": "left",
      "text": "Un wiꞥsch stahweja starp\nteam Mirruscheem/ un starp teem\nDsihweem/ tad tappe ta Mohzi-\nba norwehrsta."
    },
    {
      "n": 49,
      "column": "left",
      "text": "Kas uu no tahs Mohzibas\nnomirruschi bija/ to bija tschetr-\npadefmits tuhktoschi/ un feptin-\nfints/ besteen/ kas Korus Wai-\nnas deht nomirre."
    },
    {
      "n": 50,
      "column": "left",
      "text": "Un Aarons atgreesahs pee\nMohsus/ preeksch tahs Sa-ee-\nschanas Telts Durwim/ un ta\nMohziba wittejahs.\nTa XVII. Nodalla.\nAarona Sislis satto: 1. Par Sipmi lai ne"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Ad runnaja tas Kling\nus Mohsu/ un fazzija"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Runna us tee\nIsraeta Behrncem/ nn nem n\nteem preeksch ikweenu Tehn\nNamnu weenu Kohku/ no wi\nfeem winno Wirfneefeem/ pe\nwinno Tehwu Namuna/ divip\ndefmits Kohkus/ tew buhs ikwe\nna Wahrdiu us sawu Kohku ra\nfiht."
    },
    {
      "n": 3,
      "column": "right",
      "text": "Bet Aarona Wahrdiu but\ntew us to Kohku no tahs Lew\nZilts rakstiht/ jo ikweenam Ko\nkam buhs preeksch winno Te\nwu Namuna Wirfneefu buht."
    },
    {
      "n": 4,
      "column": "right",
      "text": "Un tew buhs tohs Sa-e-\nschanas Telti nolikt preeksch tah\nLeezibas/ kur muhsu Sa-eefsch\nnas Weeta buhs."
    },
    {
      "n": 5,
      "column": "right",
      "text": "Un tad ta Wihra Kohks\nfo es iswehleschn saltobs/ un\nkluffinaschu to Israeta Behri\nKurne-chanas prett mann/ ar\ntee prett jums turne."
    },
    {
      "n": 6,
      "column": "right",
      "text": "Un Mohsus runnaja u\nteem Israeta Behrneem/ tad d\nwe wiffi winnu Wirfneeki wi\nnam weenu Kohku/ preeksch i\nweenu Wirfneefu weenu Kohk\npehz winno Tehwu Nammo\ndiwipadefmits Kohkus/ tur a\nbija Aarona Kohks starp winn\nKohkeem."
    },
    {
      "n": 7,
      "column": "right",
      "text": "Un Mohsus nolikke tol\nKohkus preeksch to KUNG\nLeezibas Telti."
    },
    {
      "n": 8,
      "column": "right",
      "text": "Un AutaDeena/kad Mo"
    }
  ],
